insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('world','World',null,'world','Global',null,null,null,null,'The full climbing index — drill down by country, then region, to a crag or peak.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('usa','United States','world','country','North America',null,null,null,null,'Climbing across the United States, organized by state.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('utah','Utah','usa','state','United States',null,null,null,null,'From the granite of the Wasatch to the high alpine of the Uintas and the sandstone of Zion — one of the most varied climbing and mountain states in the country.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('wasatch','Wasatch Range','utah','range','Utah',null,null,null,null,'The range at Salt Lake City''s back door — alpine peaks, deep glaciated canyons, and world-class granite, all within an hour of the city.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('uintas','Uinta Mountains','utah','range','Utah',null,null,null,null,'Utah''s high, remote east–west range, home to the state''s tallest summits and big alpine objectives above 13,000 feet.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('zion','Zion National Park','utah','region','Utah',null,null,null,null,'Towering Navajo sandstone walls and exposed ridgelines in southwest Utah — iconic scrambles and big-wall objectives.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('kings','Kings Peak','uintas','peak','High Uintas',40.7763,-110.3724,13528,'UAC — Uintas',null,'seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('olympus','Mount Olympus','wasatch','peak','Wasatch Front',40.6888,-111.7677,9026,'UAC — Salt Lake',null,'seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('angels','Angels Landing','zion','peak','Zion NP',37.269,-112.9481,5790,null,null,'seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('lcc','Little Cottonwood Canyon','wasatch','canyon','Wasatch Range',40.5719,-111.7569,6800,'UAC — Salt Lake','Granite heart of the Wasatch, 20 minutes from Salt Lake — splitter cracks, glacier-polished slabs, steep sport, and world-class bouldering all in one canyon.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('lcc_egg','The Egg','lcc','crag','Little Cottonwood Canyon',40.5722,-111.7585,6300,'UAC — Salt Lake','Right above the lower-canyon Park & Ride. Popular and super-accessible, with excellent trad and sport lines and big canyon views.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('lcc_crescent','Crescent Crack Buttress','lcc','crag','Little Cottonwood Canyon',40.5731,-111.7602,6500,'UAC — Salt Lake','One of the canyon''s classic trad areas — beautiful splitter cracks and technical face climbing, single- and multi-pitch.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('lcc_fin_thumb','The Fin & The Thumb','lcc','crag','Little Cottonwood Canyon',40.576,-111.77,7200,'UAC — Salt Lake','Massive, imposing formations higher in the canyon — iconic multi-pitch trad with sustained crack climbing.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('lcc_hellgate','Hellgate Cliffs','lcc','crag','Little Cottonwood Canyon',40.575,-111.768,7000,'UAC — Salt Lake','One of LCC''s most popular sport zones — steep, pumpy routes across a wide range of grades.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('lcc_secret_garden','Secret Garden','lcc','crag','Little Cottonwood Canyon',40.574,-111.762,6600,'UAC — Salt Lake','A roadside lower-canyon bouldering area and an LCC classic — granite problems from the technical Twisted (V4) and Lance''s Dihedral (V6) to the steep, powerful Copperhead (V9).','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('colorado','Colorado','usa','state','United States',null,null,null,null,'From the alpine ice of the San Juans to the limestone of Vail and the granite of the Front Range — a deep, year-round climbing and mountaineering state.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('california','California','usa','state','United States',null,null,null,null,'Granite big walls, alpine spires, and world-class bouldering — from Yosemite Valley to the High Sierra and the desert.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('yosemite','Yosemite Valley','california','region','California',null,null,null,null,'The spiritual home of big-wall and crack climbing — glacier-polished granite walls rising thousands of feet above the Valley floor.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('co_telluride','Bridal Veil Falls','colorado','crag','Telluride, CO',37.9192,-107.77,10279,'CAIC — Northern San Juan','A north-facing box-canyon wall above Telluride that freezes into Colorado’s tallest ice climb each winter.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('co_vail','East Vail Amphitheater','colorado','crag','Vail, CO',39.6308,-106.2932,9056,'CAIC — Vail & Summit County','The shaded Designator amphitheater — limestone roofs and hanging ice that gave birth to modern mixed climbing.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('yos_wacolumn','Washington Column','yosemite','wall','Yosemite Valley, CA',37.744,-119.5553,5912,null,'A ~1,200 ft granite wall at the east end of Yosemite Valley — home to the classic introductory big wall, the South Face.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('washington','Washington','usa','state','United States',null,null,null,null,'Glaciated Cascade volcanoes and the alpine granite of the North Cascades — from Rainier and Baker to remote backcountry summits.','seed');
insert into areas (id,name,parent_id,area_type,region,lat,lng,elevation,avy_zone,blurb,source) values ('north_cascades','North Cascades','washington','range','Washington',null,null,null,null,'The iciest range in the Lower 48 — heavily glaciated peaks and the premier glacier-mountaineering terrain in the contiguous U.S.','seed');
